#include<bits/stdc++.h>
using namespace std;
long long s1,s2,s3,gentle[90],maximum,ma=-1;
int main(){
	cin>>s1>>s2>>s3;
	for(int i=1;i<=s1;i++){
		for(int j=1;j<=s2;j++){
			for(int k=1;k<=s3;k++){
				gentle[i+j+k]++;
			}
		}
	}
	for(int i=1;i<=40;i++){
		if(gentle[i]>maximum){
			maximum=gentle[i];
			ma=i;
		}
	}
	cout<<ma;
	return 0;
}
